sysauto_script.script:
var tableName = 'kb_knowledge';
var totalRecordCount = 0;
var totalAttachmentCount = 0;
var recordsWithAttachments = [];
var gr = new GlideRecord(tableName);
if (!gr.isValid()) {
    gs.print('Invalid table: ' + tableName);
} else {
    gr.addEncodedQuery(
        'sys_updated_onRELATIVELT@year@ago@5' +
        '^ORsys_created_onRELATIVELT@year@ago@5' +
        '^retiredISNOTEMPTY'
    );
    //gr.setLimit(5);
    gr.query();
    //gs.print('Total records: ' + gr.getRowCount());
    while (gr.next()) {
        totalRecordCount++;
        var hasAttachment = false;
        var attGR = new GlideRecord('sys_attachment');
        attGR.addQuery('table_name', tableName);
        attGR.addQuery('table_sys_id', gr.sys_id);
        attGR.query();
        while (attGR.next()) {
            hasAttachment = true;
            totalAttachmentCount++;
            gs.print(
                'Deleting attachment: ' + attGR.file_name +
                ' | KB Sys ID: ' + gr.sys_id
            );
            new GlideSysAttachment().deleteAttachment(attGR.sys_id);
        }
        if (hasAttachment) {
            recordsWithAttachments.push(gr.sys_id.toString());
        }
    }

    gs.print('Total Records Processed: ' + totalRecordCount);
    gs.print('Total Attachments Deleted: ' + totalAttachmentCount);
    gs.print('Records with attachments: ' + recordsWithAttachments.length);

    if (recordsWithAttachments.length > 0) {
        gs.print('Record Sys IDs: ' + recordsWithAttachments.join(', '));
    }
}
